// ── 整理分類 & 建立 Prompt ──
// Groups articles by journal+type, sorts, builds ISO week header,
// and produces a single comprehensive Gemini prompt.

const JOURNAL_ORDER = ['NEJM', 'Lancet', 'JAMA', 'BMJ'];
const TYPE_ORDER    = ['RCT', 'MA', 'SR', 'OA'];
const TYPE_DISPLAY  = {
  RCT: 'RCT', MA: 'Meta-analysis',
  SR:  'Systematic Review', OA: 'Original Article',
};

const items = $input.all().map(i => i.json);

// Stats
const stats = { RCT: 0, MA: 0, SR: 0, OA: 0 };
for (const a of items) {
  if (a.articleType in stats) stats[a.articleType]++;
}

// Group by journal + type
const grouped = {};
for (const j of JOURNAL_ORDER) {
  grouped[j] = {};
  for (const t of TYPE_ORDER) grouped[j][t] = [];
}
for (const a of items) {
  if (grouped[a.journal] && a.articleType in grouped[a.journal]) {
    grouped[a.journal][a.articleType].push(a);
  }
}
// Sort within type: newest pubDate first
for (const j of JOURNAL_ORDER)
  for (const t of TYPE_ORDER)
    grouped[j][t].sort((a, b) => new Date(b.pubDate || 0) - new Date(a.pubDate || 0));

// ISO week number (ISO 8601)
function getISOWeek(d) {
  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  const dow  = date.getUTCDay() || 7;
  date.setUTCDate(date.getUTCDate() + 4 - dow);
  const y1 = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
  return Math.ceil((((date - y1) / 86400000) + 1) / 7);
}

const now       = new Date();
const weekNum   = String(getISOWeek(now)).padStart(2, '0');
const year      = now.getFullYear();
const timestamp = now.toLocaleString('zh-TW', {
  timeZone: 'Asia/Taipei',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', hour12: false,
});
const docTitle  = '【藥師文獻週報】' + year + ' 第' + weekNum + '週';
const total     = items.length;
const SEP       = '══════════════════════════════════════';

// Format one article for the ARTICLES block
const fmtArticle = a =>
  'PMID: '     + a.pmid + '\n' +
  'Journal: '  + a.journal + '\n' +
  'Type: '     + (TYPE_DISPLAY[a.articleType] || a.articleType) + '\n' +
  'Title: '    + a.title + '\n' +
  'Author: '   + (a.firstAuthor || 'N/A') + '\n' +
  'DOI: '      + (a.doi || 'N/A') + '\n' +
  'PubDate: '  + (a.pubDate || 'N/A') + '\n' +
  'Abstract:\n' + (a.abstract || '(no abstract available)');

// Build ordered article data for the prompt
let articleData = '';
for (const j of JOURNAL_ORDER) {
  const journalArticles = TYPE_ORDER.flatMap(t => grouped[j][t]);
  if (!journalArticles.length) continue;
  articleData += '\n=== ' + j + ' ===\n';
  for (const t of TYPE_ORDER) {
    if (!grouped[j][t].length) continue;
    articleData += '\n-- ' + TYPE_DISPLAY[t] + ' --\n\n';
    for (const a of grouped[j][t]) {
      articleData += fmtArticle(a) + '\n\n---\n\n';
    }
  }
}

// Build full Gemini prompt
const prompt =
'You are a senior clinical pharmacist editor. Produce the weekly pharmacist digest.' +
'\n\n' +
'════════════════════ LANGUAGE & STYLE RULES ════════════════════\n' +
'- All explanatory text: Traditional Chinese (繁體中文)\n' +
'- Keep in English (NEVER translate or transliterate):\n' +
'    drug names, brand names, trial names, gene names, biomarkers, lab units, journal names\n' +
'- Established Chinese disease terms are acceptable (心房顫動, 糖尿病, 心衰竭, etc.)\n' +
'- NO MARKDOWN anywhere — no **, no *, no # characters\n' +
'- 背景/方法/結果: max 2 sentences each\n' +
'- 結論: exactly 1 sentence (the clinical implication for pharmacists)\n' +
'- Missing field: write （詳見原文）\n' +
'\n' +
'════════════════════ OUTPUT FORMAT (copy exactly) ════════════════════\n\n' +
'【藥師文獻週報】' + year + ' 第' + weekNum + '週\n' +
'NEJM / Lancet / JAMA / BMJ 精選\n' +
'產製時間：' + timestamp + '\n\n' +
SEP + '\n' +
'本週收錄：' + total + ' 篇\n' +
'RCT：' + stats.RCT + ' 篇｜Meta-analysis：' + stats.MA + ' 篇｜系統性回顧：' + stats.SR + ' 篇｜原著論文：' + stats.OA + ' 篇\n' +
SEP + '\n\n' +
'[For each journal that has articles, in order: NEJM → Lancet → JAMA → BMJ]\n\n' +
'【JOURNAL_NAME】\n' +
'──────────────────────────────────────\n\n' +
'[Within each journal: RCT → Meta-analysis → Systematic Review → Original Article; newest first]\n\n' +
'▶ [ORIGINAL ENGLISH TITLE — copy verbatim from Title field, NEVER translate]\n' +
'  類型：[type display name]｜作者：[Author LastName] et al.\n' +
'  DOI：[doi field value; if N/A write （詳見原文）]\n\n' +
'  背景：[≤2 sentences in Chinese]\n' +
'  方法：[≤2 sentences in Chinese: design, N, intervention vs comparator, follow-up]\n' +
'  結果：[≤2 sentences in Chinese: primary endpoint + HR/RR/OR, 95%CI, p-value]\n' +
'  結論：[exactly 1 sentence in Chinese: clinical implication for hospital pharmacists]\n\n' +
'[blank line between articles]\n\n' +
'End the entire document with: 【本週精選完畢】\n\n' +
'════════════════════ ARTICLES ════════════════════\n' +
articleData;

return [{ json: { prompt, docTitle, total, stats, timestamp, year, weekNum } }];

// ── 準備文件內容 ──
// Receives Gemini output ($json.text) and fetches docTitle from upstream.
const digestText = $json.text || '';
const meta = $('整理分類 & 建立 Prompt').first().json;
return [{ json: { digestText, docTitle: meta.docTitle } }];

// ── PubMed Fetch ──
// Runs 16 queries: 4 journals × 4 article types
// Rate-limited (400ms/150ms), PMID-deduplicated
// Returns one item per article: {pmid, journal, articleType, articleTypeLabel,
//   title, firstAuthor, abstract, doi, pubDate}

const BASE      = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/';
const TOOL_NAME = 'PharmJournalNewsletter';
const EMAIL     = $env.PUBMED_EMAIL || 'noreply@example.com';
const API_KEY   = $env.PUBMED_API_KEY || '';
const DELAY_MS  = API_KEY ? 150 : 400;

const JOURNALS = [
  { name: 'NEJM',   issn: '0028-4793' },
  { name: 'Lancet', issn: '0140-6736' },
  { name: 'JAMA',   issn: '0098-7484' },
  { name: 'BMJ',    issn: '0959-8138' },
];

const TYPES = [
  { code: 'RCT', label: 'RCT',              retmax: 5,
    filter: 'randomized controlled trial[pt]' },
  { code: 'MA',  label: 'Meta-analysis',     retmax: 5,
    filter: 'meta-analysis[pt]' },
  { code: 'SR',  label: 'Systematic Review', retmax: 5,
    filter: 'systematic review[pt]' },
  { code: 'OA',  label: 'Original Article',  retmax: 3,
    filter: 'journal article[pt] NOT (randomized controlled trial[pt] OR systematic review[pt] OR meta-analysis[pt] OR review[pt] OR letter[pt] OR editorial[pt] OR comment[pt])' },
];

// Date range: today − 7 days  [dp] = date of publication
const now    = new Date();
const cutoff = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const fmtDate = d =>
  d.getFullYear() + '/' +
  String(d.getMonth() + 1).padStart(2, '0') + '/' +
  String(d.getDate()).padStart(2, '0');
const dateRange = fmtDate(cutoff) + ':' + fmtDate(now) + '[dp]';

const sleep = ms => new Promise(r => setTimeout(r, ms));

function commonParams() {
  const p = { db: 'pubmed', tool: TOOL_NAME, email: EMAIL };
  if (API_KEY) p.api_key = API_KEY;
  return p;
}

async function eSearch(issn, typeFilter, retmax) {
  const term = issn + '[ta] AND ' + dateRange + ' AND ' + typeFilter;
  const params = Object.assign({}, commonParams(), {
    term, usehistory: 'y', retmax: String(retmax), retmode: 'json',
  });
  const resp = await fetch(BASE + 'esearch.fcgi?' + new URLSearchParams(params));
  if (!resp.ok) return [];
  const data = await resp.json();
  return (data && data.esearchresult && data.esearchresult.idlist) || [];
}

async function eFetch(ids) {
  if (!ids.length) return '';
  const params = Object.assign({}, commonParams(), {
    id: ids.join(','), rettype: 'abstract', retmode: 'xml',
  });
  const resp = await fetch(BASE + 'efetch.fcgi?' + new URLSearchParams(params));
  if (!resp.ok) return '';
  return await resp.text();
}

const MONTH_MAP = { Jan:1,Feb:2,Mar:3,Apr:4,May:5,Jun:6,
                    Jul:7,Aug:8,Sep:9,Oct:10,Nov:11,Dec:12 };

function parseArticles(xml, journal, typeCode, typeLabel) {
  const articles = [];
  const artRx = /<PubmedArticle>([sS]*?)<\/PubmedArticle>/g;
  let m;
  while ((m = artRx.exec(xml)) !== null) {
    const block = m[1];

    const getTag = tag => {
      const r = new RegExp('<' + tag + '(?:[^>]*)>([\s\S]*?)<\/' + tag + '>', 'i');
      const x = r.exec(block);
      return x ? x[1].replace(/<[^>]+>/g, '').trim() : '';
    };

    const pmid = getTag('PMID');
    if (!pmid) continue;

    const title = getTag('ArticleTitle')
      .replace(/\.$/, '')
      .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>');
    if (!title) continue;

    // First author
    const auBlock = (/<AuthorList[^>]*>([\s\S]*?)<\/AuthorList>/.exec(block) || ['',''])[1];
    const auM = /<Author[^>]*>[\s\S]*?<LastName>([^<]+)<\/LastName>(?:[\s\S]*?<ForeName>([^<]+)<\/ForeName>)?/.exec(auBlock);
    const firstAuthor = auM
      ? (auM[1] + (auM[2] ? ' ' + auM[2].charAt(0) : ''))
      : '';

    // Abstract: structured sections preferred
    const absBlock = (/<Abstract>([\s\S]*?)<\/Abstract>/.exec(block) || ['',''])[1];
    let abstract = '';
    if (absBlock) {
      const sections = [...absBlock.matchAll(/<AbstractText(?:[^>]*Label="([^"]*)")?[^>]*>([\s\S]*?)<\/AbstractText>/g)];
      if (sections.length) {
        abstract = sections.map(s =>
          (s[1] ? s[1] + ': ' : '') + s[2].replace(/<[^>]+>/g, '').trim()
        ).join('\n');
      } else {
        abstract = absBlock.replace(/<[^>]+>/g, '').trim();
      }
    }

    // DOI
    const doiM = /<ArticleId IdType="doi">([^<]+)<\/ArticleId>/i.exec(block);
    const doi = doiM ? 'https://doi.org/' + doiM[1].trim() : '';

    // PubDate
    const pdBlock = (/<PubDate>([\s\S]*?)<\/PubDate>/.exec(block) || ['',''])[1];
    const yr  = (/<Year>(\d+)<\/Year>/.exec(pdBlock)  || ['',''])[1];
    const rawM = (/<Month>([^<]+)<\/Month>/.exec(pdBlock) || ['','01'])[1];
    const dy  = (/<Day>(\d+)<\/Day>/.exec(pdBlock)   || ['','01'])[1];
    const moNum = /^\d+$/.test(rawM)
      ? rawM.padStart(2,'0')
      : String(MONTH_MAP[rawM] || 1).padStart(2,'0');
    const pubDate = yr ? yr + '-' + moNum + '-' + dy.padStart(2,'0') : '';

    articles.push({ pmid, journal, articleType: typeCode, articleTypeLabel: typeLabel,
                    title, firstAuthor, abstract, doi, pubDate });
  }
  return articles;
}

// ── Main: run 16 queries ──
const seen = new Set();
const allArticles = [];

for (const journal of JOURNALS) {
  for (const type of TYPES) {
    await sleep(DELAY_MS);
    let ids = [];
    try { ids = await eSearch(journal.issn, type.filter, type.retmax); } catch (_) {}
    const newIds = ids.filter(id => !seen.has(id));
    newIds.forEach(id => seen.add(id));
    if (newIds.length > 0) {
      await sleep(DELAY_MS);
      let xml = '';
      try { xml = await eFetch(newIds); } catch (_) {}
      if (xml) allArticles.push(...parseArticles(xml, journal.name, type.code, type.label));
    }
  }
}

return allArticles.map(a => ({ json: a }));
